<?php session_start(); require_once '../config/database.php';
if(isset($_GET['logout'])){session_destroy();header('Location:index.php');exit;}
if($_SERVER['REQUEST_METHOD']==='POST'){ $st=$pdo->prepare('SELECT * FROM admins WHERE username=? AND password=MD5(?)'); $st->execute([$_POST['username'],$_POST['password']]); if($a=$st->fetch()){$_SESSION['admin']=$a['username'];} else $err='Sai tài khoản hoặc mật khẩu'; }
if(empty($_SESSION['admin'])): ?><form method="post" style="max-width:360px;margin:80px auto;font-family:Arial"><h2>Admin Login</h2><input name="username" placeholder="admin" style="width:100%;padding:12px;margin:8px"><input name="password" type="password" placeholder="admin123" style="width:100%;padding:12px;margin:8px"><button style="padding:12px 20px">Đăng nhập</button><p><?= $err ?? '' ?></p></form><?php exit; endif;
$products=$pdo->query('SELECT p.*,c.name category FROM products p JOIN categories c ON c.id=p.category_id ORDER BY p.id DESC')->fetchAll(); $orders=$pdo->query('SELECT * FROM orders ORDER BY id DESC LIMIT 20')->fetchAll(); ?>
<!doctype html><html><meta charset="utf-8"><title>Admin</title><style>body{font-family:Arial;margin:30px}table{border-collapse:collapse;width:100%;margin:20px 0}td,th{border:1px solid #ddd;padding:10px}a{color:#111}</style><h1>Quản trị Sudes Sport</h1><a href="../index.php">Ra trang chủ</a> | <a href="?logout=1">Đăng xuất</a><h2>Sản phẩm</h2><table><tr><th>ID</th><th>Tên</th><th>Danh mục</th><th>Giá</th><th>Kho</th></tr><?php foreach($products as $p): ?><tr><td><?=$p['id']?></td><td><?=$p['name']?></td><td><?=$p['category']?></td><td><?=money_vnd(current_price($p))?></td><td><?=$p['stock']?></td></tr><?php endforeach; ?></table><h2>Đơn hàng mới</h2><table><tr><th>ID</th><th>Khách</th><th>SĐT</th><th>Tổng</th><th>Trạng thái</th></tr><?php foreach($orders as $o): ?><tr><td><?=$o['id']?></td><td><?=$o['customer_name']?></td><td><?=$o['phone']?></td><td><?=money_vnd($o['total'])?></td><td><?=$o['status']?></td></tr><?php endforeach; ?></table></html>
